            new(2, "CNC Lathe",           "Building B – Shop 1", new DateTime(2026, 4, 22)),
            new(3, "Forklift #12",        "Warehouse C",         new DateTime(2026, 5, 1)),
            new(4, "Overhead Crane",      "Building A – Bay 1",  new DateTime(2025, 12, 10)),
            new(5, "Air Compressor",      "Utility Room",        new DateTime(2026, 2, 28)),
            new(6, "Welding Station #4",  "Building B – Shop 2", new DateTime(2026, 1, 18)),
            new(7, "Band Saw",            "Building A – Bay 5",  new DateTime(2026, 5, 10)),
            new(8, "Pallet Jack #7",      "Warehouse C",         new DateTime(2026, 4, 5)),
        };
    }
}

